selector_to_html = {"a[href=\"#distinguishing-parameter-variants\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">8. </span>Distinguishing parameter variants<a class=\"headerlink\" href=\"#distinguishing-parameter-variants\" title=\"Permalink to this heading\">#</a></h1><p>We can see that there are many parameter variants, but it is not easy to see the differences in parameters between the rows that have the same <code class=\"docutils literal notranslate\"><span class=\"pre\">item_name</span></code>.</p><p>We can use the <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman.get_params_diffs()</span></code> to see the unique parameters between rows with the same <code class=\"docutils literal notranslate\"><span class=\"pre\">item_name</span></code></p>", "a[href=\"#correlation-metrics\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">9.1. </span>Correlation metrics<a class=\"headerlink\" href=\"#correlation-metrics\" title=\"Permalink to this heading\">#</a></h2><p>Create a couple of summary images of the movie, including:</p>", "a[href=\"#optional-cleanup-dataframe\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">10. </span>Optional, cleanup DataFrame<a class=\"headerlink\" href=\"#optional-cleanup-dataframe\" title=\"Permalink to this heading\">#</a></h1><p>Use the index that works best and all other items.</p><p>Remove batch items (i.e. rows) using <code class=\"docutils literal notranslate\"><span class=\"pre\">df.caiman.remove_item(&lt;item_uuid&gt;)</span></code>. This also cleans up the output data in the batch directory.</p>", "a[href=\"#apply-registration-using-the-same-parameters-to-the-remaining-z-planes\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">10.2. </span>Apply registration using the same parameters to the remaining z-planes<a class=\"headerlink\" href=\"#apply-registration-using-the-same-parameters-to-the-remaining-z-planes\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"#user-input-input-data-path-and-plane-number\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.4. </span>User input: input data path and plane number<a class=\"headerlink\" href=\"#user-input-input-data-path-and-plane-number\" title=\"Permalink to this heading\">#</a></h2><p>the same path as <span class=\"xref myst\">pre_processing</span>\nparent_dir = Path().home() / \u2018caiman_data\u2019 / \u2018animal_01\u2019 / \u2018session_01\u2019</p>", "a[href=\"#use-the-varients-to-organize-results-to-run-multiple-batch-items\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">9. </span>Use the varients to organize results to run multiple batch items.<a class=\"headerlink\" href=\"#use-the-varients-to-organize-results-to-run-multiple-batch-items\" title=\"Permalink to this heading\">#</a></h1><p><code class=\"docutils literal notranslate\"><span class=\"pre\">df.iterrows()</span></code> iterates through rows and returns the numerical index and row for each iteration</p>", "a[href=\"#logging\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.2. </span>Logging<a class=\"headerlink\" href=\"#logging\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"#lbm-step-2-registration\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4. </span>LBM Step 2: Registration<a class=\"headerlink\" href=\"#lbm-step-2-registration\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">4.1. </span>Registration: Correct for rigid/non-rigid movement<a class=\"headerlink\" href=\"#registration-correct-for-rigid-non-rigid-movement\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"#default-registration-parameters\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5. </span>Default registration parameters<a class=\"headerlink\" href=\"#default-registration-parameters\" title=\"Permalink to this heading\">#</a></h1><p>The parameters are passed <strong>directly</strong> to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>, this means you need to use the same exact names for the parameters and you can use all the parameters that you can use with <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code> - because it\u2019s just passing them to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>.</p><p>The parameters dict for a mesmerize batch item must have the following structure. Put all the parameters in a dict under a key called <strong>main</strong>. The <strong>main</strong> dict is then fed directly to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>.</p>", "a[href=\"#pixel-shifts\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">9.2. </span>Pixel Shifts<a class=\"headerlink\" href=\"#pixel-shifts\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"#optional-view-hardware-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.3. </span>(optional): View hardware information<a class=\"headerlink\" href=\"#optional-view-hardware-information\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"#first-registration-run-preset-with-good-defaults\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6. </span>First registration run: preset with good defaults<a class=\"headerlink\" href=\"#first-registration-run-preset-with-good-defaults\" title=\"Permalink to this heading\">#</a></h1><p>Technical notes: On Linux &amp; Mac it will run in subprocess but on Windows it will run in the local kernel.</p>", "a[href=\"#registration-grid-search-if-you-need-it\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">7. </span>Registration Grid Search (if you need it!)<a class=\"headerlink\" href=\"#registration-grid-search-if-you-need-it\" title=\"Permalink to this heading\">#</a></h1><p>More runs with varying parameters, stored on disk in the dataframe batch.pickle</p>", "a[href=\"#registration-correct-for-rigid-non-rigid-movement\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.1. </span>Registration: Correct for rigid/non-rigid movement<a class=\"headerlink\" href=\"#registration-correct-for-rigid-non-rigid-movement\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"#preview-motion-correction\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1. </span>Preview Motion Correction<a class=\"headerlink\" href=\"#preview-motion-correction\" title=\"Permalink to this heading\">#</a></h2><p>Before running a grid search for the best parameter set, preview your registration results</p>", "a[href=\"#evaluate-results-optical-flow\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">10.1. </span>Evaluate Results: Optical Flow<a class=\"headerlink\" href=\"#evaluate-results-optical-flow\" title=\"Permalink to this heading\">#</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
